#include <stdio.h>
int main() {
    int T, N, count, x;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        count = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &x);
            if (x % 2 != 0) count++;
        }
        if (count <= 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

