code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i == 0) T = parseInt(line);
    else input.push(line);
    i++;
    if (i == T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let N = parseInt(input[j * 2]);
            let count = 0;
            let arr = input[j * 2 + 1].split(' ').map(x => parseInt(x));
            for (let k = 0; k < N; k++) {
                if (arr[k] % 2 != 0) count++;
            }
            if (count <= 1) console.log('YES');
            else console.log('NO');
        }
    }
});
